import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import api from '../services/api';
import toast from 'react-hot-toast';

const OTPVerificationPage = () => {
  const [emailOTP, setEmailOTP] = useState('');
  const [phoneOTP, setPhoneOTP] = useState('');
  const [loading, setLoading] = useState(false);
  const [resendLoading, setResendLoading] = useState(false);
  const [resendTimer, setResendTimer] = useState(0);
  const [currentStep, setCurrentStep] = useState('email'); // email or phone
  
  const navigate = useNavigate();
  const location = useLocation();
  const registrationData = location.state?.registrationData;

  useEffect(() => {
    // Redirect if no registration data
    if (!registrationData) {
      navigate('/register');
      return;
    }
  }, [registrationData, navigate]);

  // Timer for resend OTP
  useEffect(() => {
    if (resendTimer > 0) {
      const timer = setTimeout(() => setResendTimer(resendTimer - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [resendTimer]);

  const handleVerifyEmail = async (e) => {
    e.preventDefault();
    
    if (!emailOTP || emailOTP.length !== 6) {
      toast.error('Please enter a valid 6-digit OTP');
      return;
    }

    setLoading(true);
    try {
      const response = await api.post('/auth/verify-email-otp', {
        email: registrationData.email,
        otp: emailOTP
      });

      if (response.data.success) {
        toast.success('Email verified successfully');
        setCurrentStep('phone');
        setEmailOTP('');
      } else {
        toast.error(response.data.message || 'Invalid OTP');
      }
    } catch (error) {
      console.error('Email OTP verification error:', error);
      toast.error(error.response?.data?.message || 'OTP verification failed');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyPhone = async (e) => {
    e.preventDefault();
    
    if (!phoneOTP || phoneOTP.length !== 6) {
      toast.error('Please enter a valid 6-digit OTP');
      return;
    }

    setLoading(true);
    try {
      const response = await api.post('/auth/verify-phone-otp', {
        phone: registrationData.phone,
        otp: phoneOTP
      });

      if (response.data.success) {
        toast.success('Phone verified successfully');
        
        // Complete registration
        completeRegistration();
      } else {
        toast.error(response.data.message || 'Invalid OTP');
      }
    } catch (error) {
      console.error('Phone OTP verification error:', error);
      toast.error(error.response?.data?.message || 'OTP verification failed');
    } finally {
      setLoading(false);
    }
  };

  const completeRegistration = async () => {
    setLoading(true);
    try {
      const response = await api.post('/auth/complete-registration', registrationData);

      if (response.data.success) {
        toast.success('Registration successful! Redirecting to login...');
        setTimeout(() => {
          navigate('/login');
        }, 2000);
      } else {
        toast.error(response.data.message || 'Registration failed');
      }
    } catch (error) {
      console.error('Registration completion error:', error);
      toast.error(error.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  const handleResendOTP = async (type) => {
    if (resendTimer > 0) return;

    setResendLoading(true);
    try {
      const endpoint = type === 'email' ? '/auth/resend-email-otp' : '/auth/resend-phone-otp';
      const data = type === 'email' 
        ? { email: registrationData.email } 
        : { phone: registrationData.phone };

      const response = await api.post(endpoint, data);

      if (response.data.success) {
        toast.success(`OTP sent to your ${type}`);
        setResendTimer(60);
      } else {
        toast.error(response.data.message || `Failed to send OTP to ${type}`);
      }
    } catch (error) {
      console.error(`Resend ${type} OTP error:`, error);
      toast.error(error.response?.data?.message || `Failed to send OTP to ${type}`);
    } finally {
      setResendLoading(false);
    }
  };

  if (!registrationData) {
    return null;
  }

  return (
    <div className="container">
      <div className="auth-container" style={{ maxWidth: '500px' }}>
        <h1>Verify Your Details</h1>

        {currentStep === 'email' && (
          <div>
            <div style={{
              background: '#e3f2fd',
              padding: '15px',
              borderRadius: '8px',
              marginBottom: '20px',
              textAlign: 'center'
            }}>
              <p style={{ margin: 0, color: '#1976d2' }}>
                We sent an OTP to <strong>{registrationData.email}</strong>
              </p>
            </div>

            <form onSubmit={handleVerifyEmail}>
              <div className="form-group">
                <label>Email OTP (6 digits)</label>
                <input
                  type="text"
                  className="form-control"
                  value={emailOTP}
                  onChange={(e) => setEmailOTP(e.target.value.replace(/\D/g, '').slice(0, 6))}
                  placeholder="000000"
                  maxLength="6"
                  required
                  style={{ fontSize: '24px', textAlign: 'center', letterSpacing: '5px' }}
                />
              </div>

              <button
                type="submit"
                className="btn btn-primary btn-block"
                disabled={loading}
              >
                {loading ? 'Verifying...' : 'Verify Email OTP'}
              </button>
            </form>

            <p style={{ textAlign: 'center', marginTop: '15px', fontSize: '14px' }}>
              Didn't receive OTP?{' '}
              <button
                onClick={() => handleResendOTP('email')}
                disabled={resendTimer > 0 || resendLoading}
                style={{
                  background: 'none',
                  border: 'none',
                  color: '#1976d2',
                  cursor: 'pointer',
                  textDecoration: 'underline',
                  fontWeight: 'bold'
                }}
              >
                {resendTimer > 0 ? `Resend in ${resendTimer}s` : 'Resend'}
              </button>
            </p>
          </div>
        )}

        {currentStep === 'phone' && (
          <div>
            <div style={{
              background: '#f3e5f5',
              padding: '15px',
              borderRadius: '8px',
              marginBottom: '20px',
              textAlign: 'center'
            }}>
              <p style={{ margin: 0, color: '#7b1fa2' }}>
                We sent an OTP to <strong>{registrationData.phone}</strong>
              </p>
            </div>

            <form onSubmit={handleVerifyPhone}>
              <div className="form-group">
                <label>Mobile OTP (6 digits)</label>
                <input
                  type="text"
                  className="form-control"
                  value={phoneOTP}
                  onChange={(e) => setPhoneOTP(e.target.value.replace(/\D/g, '').slice(0, 6))}
                  placeholder="000000"
                  maxLength="6"
                  required
                  style={{ fontSize: '24px', textAlign: 'center', letterSpacing: '5px' }}
                />
              </div>

              <button
                type="submit"
                className="btn btn-primary btn-block"
                disabled={loading}
              >
                {loading ? 'Verifying...' : 'Verify Phone OTP'}
              </button>
            </form>

            <p style={{ textAlign: 'center', marginTop: '15px', fontSize: '14px' }}>
              Didn't receive OTP?{' '}
              <button
                onClick={() => handleResendOTP('phone')}
                disabled={resendTimer > 0 || resendLoading}
                style={{
                  background: 'none',
                  border: 'none',
                  color: '#7b1fa2',
                  cursor: 'pointer',
                  textDecoration: 'underline',
                  fontWeight: 'bold'
                }}
              >
                {resendTimer > 0 ? `Resend in ${resendTimer}s` : 'Resend'}
              </button>
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default OTPVerificationPage;
